                fromAccountID: nil,
                toAccountID: accountID,
                amount: amount,
                currencyCode: accounts[index].currencyCode,
                type: .credit,
                reference: reference
            )

            var transactions = try store.fetchTransactions()
            transactions.append(transaction)

            try store.saveAccounts(accounts)
            try store.saveTransactions(transactions)

            return transaction
        }
